@Finset.sum_add_distrib : ∀ {ι : Type u_1} {M : Type u_2} {s : Finset ι} [inst : AddCommMonoid M] {f g : ι → M},
  ∑ x ∈ s, (f x + g x) = ∑ x ∈ s, f x + ∑ x ∈ s, g x
@Finset.sum_const : ∀ {ι : Type u_1} {M : Type u_2} {s : Finset ι} [inst : AddCommMonoid M] (b : M),
  ∑ _x ∈ s, b = s.card • b
@Finset.card_eq_sum_ones : ∀ {ι : Type u_1} (s : Finset ι), s.card = ∑ x ∈ s, 1
@Finset.sum_eq_card_nsmul : ∀ {ι : Type u_1} {M : Type u_2} {s : Finset ι} [inst : AddCommMonoid M] {f : ι → M} {b : M},
  (∀ a ∈ s, f a = b) → ∑ a ∈ s, f a = s.card • b
Finset.range_zero : Finset.range 0 = ∅
@Finset.sum_range_zero : ∀ {M : Type u_1} [inst : AddCommMonoid M] (f : ℕ → M), ∑ k ∈ Finset.range 0, f k = 0

